/* =========================================================
   SkillsAllYouNeed — data + behaviour
   ========================================================= */

/* ───── Unique SVG ID helper (prevents gradient/mask ID collisions) ───── */
let _glyphSeq = 0;
function uniqueSvg(svg) {
  const n = ++_glyphSeq;
  let out = svg;
  out = out.replace(/\bid\s*=\s*"([^"]+)"/g, (_, d) => `id="${d}-${n}"`);
  out = out.replace(/\burl\s*\(\s*#([^)\s]+)\s*\)/g, (_, r) => `url(#${r}-${n})`);
  return out;
}

