/* ───── Merge custom skills from localStorage into SKILLS ───── */
(function(){
  try{
    const custom = JSON.parse(localStorage.getItem("skills-custom")||"[]");
    custom.forEach(s=>{ if(!SKILLS.find(x=>x.id===s.id)) SKILLS.push(s); });
  }catch(e){}
})();

