/* ───── Helpers ───── */
const escapeHTML = s => s.replace(/[&<>"']/g, c => ({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]));
const codeBacktick = s => s.replace(/`([^`]+)`/g, '<code class="inline-code">$1</code>');
const splitTriggers  = s => s.replace(/·/g, '<br><span class="trigger-sep">·</span> ');
